import{_ as e,o as a,c as n,ae as i}from"./chunks/framework.DOXEjmrP.js";const u=JSON.parse('{"title":"English Listen WinUI - Modern English Dictation Training Tool","description":"","frontmatter":{},"headers":[],"relativePath":"en/english-listen-winui.md","filePath":"en/english-listen-winui.md"}'),r={name:"en/english-listen-winui.md"};function o(s,t,l,d,c,h){return a(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="english-listen-winui-modern-english-dictation-training-tool" tabindex="-1">English Listen WinUI - Modern English Dictation Training Tool <a class="header-anchor" href="#english-listen-winui-modern-english-dictation-training-tool" aria-label="Permalink to &quot;English Listen WinUI - Modern English Dictation Training Tool&quot;">​</a></h1><p>Full migration from Qt6 to <strong>WinUI 3</strong>, redefining English dictation training with Windows 11 native experience.</p><h2 id="project-introduction" tabindex="-1">Project Introduction <a class="header-anchor" href="#project-introduction" aria-label="Permalink to &quot;Project Introduction&quot;">​</a></h2><h3 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h3><p>English Listen WinUI is a completely redesigned version of English Listen, migrated from Qt6/C++ to the WinUI 3 framework, adopting modern Windows native interface design. The project uses a <strong>C# + C++ hybrid development</strong> architecture — C# (WinUI 3) handles the modern user interface, while C++ NativeBackend handles performance-sensitive dictation logic, seamlessly connected through P/Invoke interop. Current version: v2.7.0.</p><h3 id="core-differences-from-qt6-version" tabindex="-1">Core Differences from Qt6 Version <a class="header-anchor" href="#core-differences-from-qt6-version" aria-label="Permalink to &quot;Core Differences from Qt6 Version&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>Qt6 Version</th><th>WinUI 3 Version</th></tr></thead><tbody><tr><td>UI Framework</td><td>Qt6 Widgets</td><td>WinUI 3 (Windows App SDK)</td></tr><tr><td>Development Language</td><td>C++17</td><td>C# 13 + C++ Native</td></tr><tr><td>Architecture Pattern</td><td>Simple MVC</td><td>Complete MVVM</td></tr><tr><td>Visual Style</td><td>Cross-platform style</td><td>Windows 11 native Mica material</td></tr><tr><td>Translation Service</td><td>None</td><td>Baidu Translation API integration</td></tr><tr><td>Auto Update</td><td>Manual</td><td>In-app auto update</td></tr><tr><td>Speech Engine</td><td>SAPI + Flite</td><td>Windows SAPI / Windows TTS</td></tr></tbody></table><h3 id="core-features" tabindex="-1">Core Features <a class="header-anchor" href="#core-features" aria-label="Permalink to &quot;Core Features&quot;">​</a></h3><h4 id="intelligent-vocabulary-management" tabindex="-1">Intelligent Vocabulary Management <a class="header-anchor" href="#intelligent-vocabulary-management" aria-label="Permalink to &quot;Intelligent Vocabulary Management&quot;">​</a></h4><ul><li><strong>Flexible Editing</strong>: Add/delete words freely, support batch operations</li><li><strong>File Management</strong>: Support TXT, CSV multi-format import/export, multi-level classification management</li><li><strong>Intelligent Saving</strong>: Automatically save learning records, real-time synchronization of temporary vocabulary</li><li><strong>Group Management</strong>: Support creation, editing, deletion of vocabulary groups, drag-and-drop management</li><li><strong>Search and Filtering</strong>: Quick word search, filtering by first letter, numbers, etc.</li><li><strong>Batch Translation</strong>: Integrated Baidu Translation API, one-click translation of entire vocabulary</li></ul><h4 id="personalized-training-control" tabindex="-1">Personalized Training Control <a class="header-anchor" href="#personalized-training-control" aria-label="Permalink to &quot;Personalized Training Control&quot;">​</a></h4><ul><li><strong>Time Adjustment</strong>: Freely set reading intervals (1-60 seconds), countdown display</li><li><strong>Playback Control</strong>: Pause/resume functionality, control training rhythm at any time</li><li><strong>Quick Navigation</strong>: Previous/next word quick switching</li><li><strong>Repeat Playback</strong>: Reinforce memory effect, spacebar quick repeat</li><li><strong>Random Order</strong>: Support random playback mode, increase challenge</li><li><strong>Translation Display</strong>: Chinese translation can be displayed simultaneously during dictation</li></ul><h4 id="intelligent-dictation-modes" tabindex="-1">Intelligent Dictation Modes <a class="header-anchor" href="#intelligent-dictation-modes" aria-label="Permalink to &quot;Intelligent Dictation Modes&quot;">​</a></h4><ul><li><strong>Online Mode</strong>: Listen and input in the input box, system judges correctness in real-time, support Enter submission</li><li><strong>Paper-and-Pencil Mode</strong>: Record on paper, manually input correct count at the end</li><li><strong>Levenshtein Algorithm</strong>: Intelligent spelling check, provide similar word suggestions</li></ul><h4 id="learning-progress-tracking" tabindex="-1">Learning Progress Tracking <a class="header-anchor" href="#learning-progress-tracking" aria-label="Permalink to &quot;Learning Progress Tracking&quot;">​</a></h4><ul><li><strong>Four Statistical Cards</strong>: Total test times, average accuracy, total learned words, consecutive learning days</li><li><strong>Accuracy Trend Chart</strong>: Line chart drawn with Canvas</li><li><strong>Test History List</strong>: Each record shows vocabulary name, time, correct count/total, accuracy rate</li><li><strong>Export CSV</strong> and clear records functionality</li></ul><h4 id="visual-experience" tabindex="-1">Visual Experience <a class="header-anchor" href="#visual-experience" aria-label="Permalink to &quot;Visual Experience&quot;">​</a></h4><ul><li><strong>Mica Background Material</strong>: Windows 11 native transparent effect</li><li><strong>Theme Switching</strong>: Follow system / Light / Dark three levels</li><li><strong>NavigationView</strong>: Left sidebar navigation, modern Windows app style</li><li><strong>Responsive Layout</strong>: Adapt to various screen sizes</li></ul><h3 id="usage-scenarios" tabindex="-1">Usage Scenarios <a class="header-anchor" href="#usage-scenarios" aria-label="Permalink to &quot;Usage Scenarios&quot;">​</a></h3><ul><li><strong>Students</strong>: After-class English dictation practice, multi-user system supports independent learning data</li><li><strong>Teachers</strong>: Classroom dictation testing tool, paper-and-pencil/online dual mode</li><li><strong>Self-learners</strong>: Visual charts track learning progress, consecutive learning days statistics</li><li><strong>Training institutions</strong>: Multi-user management, each user&#39;s data is independently isolated</li></ul><h2 id="technical-architecture" tabindex="-1">Technical Architecture <a class="header-anchor" href="#technical-architecture" aria-label="Permalink to &quot;Technical Architecture&quot;">​</a></h2><h3 id="technology-stack" tabindex="-1">Technology Stack <a class="header-anchor" href="#technology-stack" aria-label="Permalink to &quot;Technology Stack&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Technical Component</th><th>Version/Description</th><th>Purpose</th></tr></thead><tbody><tr><td>UI Framework</td><td>WinUI 3</td><td>Windows native interface framework</td></tr><tr><td>Frontend Language</td><td>C# 13</td><td>ViewModel, Services, Models</td></tr><tr><td>Backend Engine</td><td>C++ Native</td><td>Dictation logic, timer, voice control</td></tr><tr><td>Runtime</td><td>.NET 8.0</td><td>Cross-platform runtime</td></tr><tr><td>Windows App SDK</td><td>1.8+</td><td>Windows application development SDK</td></tr><tr><td>Speech Synthesis</td><td>Windows SAPI / System.Speech</td><td>System voice engine</td></tr><tr><td>Translation Service</td><td>Baidu Translation API</td><td>HTTP calls with cache and quota</td></tr><tr><td>Data Serialization</td><td>Newtonsoft.Json</td><td>JSON serialization/deserialization</td></tr><tr><td>Application Packaging</td><td>MSIX</td><td>Windows application packaging</td></tr><tr><td>Architecture Pattern</td><td>MVVM</td><td>Model-View-ViewModel</td></tr></tbody></table><h3 id="layered-architecture" tabindex="-1">Layered Architecture <a class="header-anchor" href="#layered-architecture" aria-label="Permalink to &quot;Layered Architecture&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────┐</span></span>
<span class="line"><span>│              Views (XAML Pages)              │</span></span>
<span class="line"><span>│  HomePage, WordsPage, DictationTestPage,     │</span></span>
<span class="line"><span>│  ProgressPage, SettingsPage, UserPage, etc.   │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│            ViewModels (C#)                   │</span></span>
<span class="line"><span>│  MainViewModel, ModernDictationViewModel,    │</span></span>
<span class="line"><span>│  ViewModelBase, RelayCommand                  │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│             Services (C#)                     │</span></span>
<span class="line"><span>│  SpeechService, ModernDictationService,      │</span></span>
<span class="line"><span>│  SettingsService, BaiduTranslateService,     │</span></span>
<span class="line"><span>│  UpdateService, ChartService, PasswordService│</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│          Native Backend (C++)                │</span></span>
<span class="line"><span>│  DictationBackend, NativeDictationExports,   │</span></span>
<span class="line"><span>│  QT6DictationBackend, TestBackend            │</span></span>
<span class="line"><span>├─────────────────────────────────────────────┤</span></span>
<span class="line"><span>│             Models (C#)                      │</span></span>
<span class="line"><span>│  Word, WordList, WordListGroup,              │</span></span>
<span class="line"><span>│  UserData, TestResult, AppSettings, VoiceInfo│</span></span>
<span class="line"><span>└─────────────────────────────────────────────┘</span></span></code></pre></div><h3 id="c-and-c-interop" tabindex="-1">C# and C++ Interop <a class="header-anchor" href="#c-and-c-interop" aria-label="Permalink to &quot;C# and C++ Interop&quot;">​</a></h3><p>C++ NativeBackend is exported through C API (<code>extern &quot;C&quot;</code>), and the C# side makes P/Invoke calls through <code>NativeMethods.cs</code>. The C++ side implements a complete <code>DictationBackend</code> class, including vocabulary management, timers, voice control, callback mechanisms, etc.</p><h3 id="development-environment" tabindex="-1">Development Environment <a class="header-anchor" href="#development-environment" aria-label="Permalink to &quot;Development Environment&quot;">​</a></h3><ul><li><strong>IDE</strong>: Visual Studio 2026</li><li><strong>Workloads</strong>: C++ Desktop Development + .NET Desktop Development</li><li><strong>Windows SDK</strong>: 10.0.26100 or higher</li><li><strong>CMake</strong>: 3.16+ (compile Native Backend)</li><li><strong>.NET SDK</strong>: 10.0</li></ul><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><h3 id="minimum-configuration" tabindex="-1">Minimum Configuration <a class="header-anchor" href="#minimum-configuration" aria-label="Permalink to &quot;Minimum Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 10 version 17763+</td></tr><tr><td>Runtime</td><td>.NET 8.0 / 10.0 Runtime</td></tr><tr><td>Processor</td><td>x64 / ARM64 / x86</td></tr><tr><td>Memory</td><td>2GB RAM</td></tr><tr><td>Storage</td><td>100MB</td></tr></tbody></table><h3 id="recommended-configuration" tabindex="-1">Recommended Configuration <a class="header-anchor" href="#recommended-configuration" aria-label="Permalink to &quot;Recommended Configuration&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Item</th><th>Requirement</th></tr></thead><tbody><tr><td>Operating System</td><td>Windows 11 24H2+</td></tr><tr><td>Processor</td><td>Intel Core i5 or higher</td></tr><tr><td>Memory</td><td>4GB RAM or higher</td></tr><tr><td>Storage</td><td>100MB</td></tr></tbody></table><h2 id="quick-start" tabindex="-1">Quick Start <a class="header-anchor" href="#quick-start" aria-label="Permalink to &quot;Quick Start&quot;">​</a></h2><ol><li><strong>Start Program</strong>: Double-click the desktop shortcut or start from the start menu</li><li><strong>Add Words</strong>: Navigate to the &quot;View Words&quot; page through the sidebar, add or import vocabulary</li><li><strong>Select Words</strong>: Check the words to dictate in the word list</li><li><strong>Start Test</strong>: Click &quot;Start Dictation&quot;, select dictation mode (paper-and-pencil/online)</li><li><strong>View Results</strong>: Check answers and statistics after the test</li><li><strong>Track Progress</strong>: After logging in, you can view detailed learning data on the &quot;Learning Progress&quot; page</li></ol><h3 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Shortcut</th><th>Function</th></tr></thead><tbody><tr><td>Spacebar</td><td>Repeat reading current word</td></tr><tr><td>Left Arrow</td><td>Return to previous word</td></tr><tr><td>Right Arrow</td><td>Jump to next word</td></tr><tr><td>ESC</td><td>Pause/resume test</td></tr><tr><td>Enter</td><td>Confirm input</td></tr></tbody></table><h2 id="open-source-address" tabindex="-1">Open Source Address <a class="header-anchor" href="#open-source-address" aria-label="Permalink to &quot;Open Source Address&quot;">​</a></h2><h3 id="code-repository" tabindex="-1">Code Repository <a class="header-anchor" href="#code-repository" aria-label="Permalink to &quot;Code Repository&quot;">​</a></h3><ul><li><strong>GitHub</strong>: <a href="https://github.com/dongzheyu/English-Listen-WinUI" target="_blank" rel="noreferrer">https://github.com/dongzheyu/English-Listen-WinUI</a></li><li><strong>Gitee</strong>: <a href="https://gitee.com/jetcpp/English-Listen-WinUI" target="_blank" rel="noreferrer">https://gitee.com/jetcpp/English-Listen-WinUI</a></li></ul><h3 id="project-information" tabindex="-1">Project Information <a class="header-anchor" href="#project-information" aria-label="Permalink to &quot;Project Information&quot;">​</a></h3><ul><li><strong>Issue Feedback</strong>: <a href="https://github.com/dongzheyu/English-Listen-WinUI/issues" target="_blank" rel="noreferrer">GitHub Issues</a></li><li><strong>Feature Suggestions</strong>: <a href="https://github.com/dongzheyu/English-Listen-WinUI/discussions" target="_blank" rel="noreferrer">GitHub Discussions</a></li></ul><h2 id="download-address" tabindex="-1">Download Address <a class="header-anchor" href="#download-address" aria-label="Permalink to &quot;Download Address&quot;">​</a></h2><ul><li><strong>Microsoft Store Local</strong>: <a href="ms-windows-store://pdp/?productid=9PLK90CNTJBG">ms-windows-store://pdp/?productid=9PLK90CNTJBG</a></li><li><strong>Microsoft Store Web</strong>: <a href="https://apps.microsoft.com/detail/9PLK90CNTJBG" target="_blank" rel="noreferrer">https://apps.microsoft.com/detail/9PLK90CNTJBG</a></li></ul><h2 id="update-records" tabindex="-1">Update Records <a class="header-anchor" href="#update-records" aria-label="Permalink to &quot;Update Records&quot;">​</a></h2><h3 id="v2-7-0-winui3-version" tabindex="-1">v2.7.0 (WinUI3 Version) <a class="header-anchor" href="#v2-7-0-winui3-version" aria-label="Permalink to &quot;v2.7.0 (WinUI3 Version)&quot;">​</a></h3><ul><li>Completely redesigned interface based on WinUI 3 framework</li><li>NavigationView sidebar navigation</li><li>Windows 11 24H2+ high-quality voice support</li><li>Intelligent voice engine (Windows SAPI / Windows TTS)</li><li>Voice preview functionality, support separate selection of English/Chinese voices</li><li>In-app auto update system</li><li>Complete MVVM architecture (ViewModelBase + RelayCommand)</li><li>C# + C++ hybrid language development (NativeBackend)</li><li>Dark/light/follow system three-level theme</li><li>User account system (login/registration/multi-user management)</li><li>Vocabulary management (add, delete, import, export, group)</li><li>Learning progress statistics (accuracy trend chart, history records)</li><li>Baidu Translation API integration (with cache and daily quota management)</li><li>Levenshtein edit distance intelligent spelling check</li><li>Keyboard shortcut support</li></ul><h3 id="license" tabindex="-1">License <a class="header-anchor" href="#license" aria-label="Permalink to &quot;License&quot;">​</a></h3><p>MIT License - Copyright (c) 2026 dongle</p><hr><p><em>Make English learning simpler and more efficient!</em></p>`,52)])])}const p=e(r,[["render",o]]);export{u as __pageData,p as default};
